insert into asm_reaction_data values (11130501, 1, 1, 1305, 0, 0, 0, 1, 0.0, 1, 0, 'vo_minigame_1012_incorrect_126', '全部が間違いじゃないわ！');
insert into asm_reaction_data values (11300101, 1, 1, 3001, 10, 10, 1, 7, 3.18, 8, 4, 'vo_minigame_1012_result_1000', 'フフ、全問正解よ！\\nちゃんと勉強してるみたいで\\n感心だわ♪');
insert into asm_reaction_data values (11300102, 1, 1, 3001, 10, 10, 1, 8, 3.33, 7, 10, 'vo_minigame_1012_result_1001', 'すごいじゃない…全問正解よ！\\nま、当然といや当然よね～\\nだってあたしが\\n教えてやってんだから♪');
insert into asm_reaction_data values (11300103, 1, 1, 3001, 10, 10, 1, 8, 5.41, 1, 10, 'vo_minigame_1012_result_1002', '全問正解！\u3000パチパチパチ～♪\\nこの難易度はもう完璧じゃない？\\n次はもっと難しい問題に挑戦よ！\\nあんたならできるって！');
insert into asm_reaction_data values (11300104, 1, 1, 3001, 10, 10, 2, 5, 8.11, 8, 10, 'vo_minigame_1012_result_1003', 'へえ…難しい問題を選んだのに\\n全問正解できてるじゃない！！\\nちょっとあんたすごすぎだわ…！\\nパーフェクトよパーフェクト！');
insert into asm_reaction_data values (11300105, 1, 1, 3001, 10, 10, 2, 10, 1.31, 5, 0, 'vo_minigame_1012_result_1004', 'まる…まる…全部まる！\\n難しい問題なのに全問正解よ…！\\n驚いた…あんたいつの間に、\\nこんなに勉強してたのよ！');
insert into asm_reaction_data values (11300106, 1, 1, 3001, 10, 10, 2, 9, 4.93, 8, 0, 'vo_minigame_1012_result_1005', 'ここまで完璧に正解されちゃうと\\nちょっと悔しいわね…！\\nけど素直に褒めてやるわ！\\nえらい、えらい、えら～い！');
insert into asm_reaction_data values (11300107, 1, 1, 3001, 10, 10, 3, 5, 2.99, 8, 4, 'vo_minigame_1012_result_1006', 'すごい…あんたパーフェクトよ！\\nこのままいけば次の試験、\\n学年一位も夢じゃないかもね！\\n楽しみだわ～♪');
insert into asm_reaction_data values (11300108, 1, 1, 3001, 10, 10, 3, 8, 8.37, 7, 4, 'vo_minigame_1012_result_1007', '満点よ！\u3000フフ、もうあんたに\\n教えることはなにもないわ…！\\n逆にあたしがあんたに教わりたい\\nくらいよ！\u3000…ね、先生♪');
insert into asm_reaction_data values (11300109, 1, 1, 3001, 10, 10, 3, 7, 5.32, 5, 8, 'vo_minigame_1012_result_1008', '全・問・正・解！\\n超難問揃いなのにすごいわね…！\\nもしかしてだけど、\\nあんたって天才！？');
insert into asm_reaction_data values (11300110, 1, 1, 3001, 9, 7, 1, 7, 4.77, 1, 4, 'vo_minigame_1012_result_1009', 'お、かなりいい点数ね～！\\nあたしも教えがいがあるわ♪\\nさ、まだまだ勉強するわよ！');
insert into asm_reaction_data values (11300111, 1, 1, 3001, 9, 7, 1, 8, 2.97, 7, 4, 'vo_minigame_1012_result_1010', 'うん、いい感じで点取れてるわ！\\nこの調子で次は、\\n満点を見せてほしいわね！');
insert into asm_reaction_data values (11300112, 1, 1, 3001, 9, 7, 1, 5, 3.47, 1, 0, 'vo_minigame_1012_result_1011', 'あ～惜しい！\\nもうちょっとで満点じゃない！\\n次はパーフェクトいけるわ！\\n頑張りましょ！');
insert into asm_reaction_data values (11300113, 1, 1, 3001, 9, 7, 2, 8, 5.32, 7, 4, 'vo_minigame_1012_result_1012', 'すごい、かなりできてるわよ！\\n難しい問題なのにやるじゃない！\\nあとは目指せ、満点ね！');
insert into asm_reaction_data values (11300114, 1, 1, 3001, 9, 7, 2, 8, 6.49, 7, 10, 'vo_minigame_1012_result_1013', 'うん、かなりいい感じよ！\\nあんたには赤点の心配なんて\\nまーったくなさそうね♪\\nでも勉強はやめさせないけど！');
insert into asm_reaction_data values (11300115, 1, 1, 3001, 9, 7, 2, 5, 3.56, 1, 0, 'vo_minigame_1012_result_1014', 'あーあとちょっとで\\n全問正解だったのに！\\n難しい問題だけどあんたなら\\n次は満点狙えるわ！');
insert into asm_reaction_data values (11300116, 1, 1, 3001, 9, 7, 3, 8, 5.67, 1, 10, 'vo_minigame_1012_result_1015', 'うん、ほとんど正解よ！\\nこんな難しい問題なのに、\\nすごいじゃない！\\nやっぱりあんた只者じゃないわ！');
insert into asm_reaction_data values (11300117, 1, 1, 3001, 9, 7, 3, 7, 2.85, 1, 10, 'vo_minigame_1012_result_1016', '着実に成長してるって感じね？\\nあんたならこの難問でも、\\nいつか満点取れちゃうかも…！');
insert into asm_reaction_data values (11300118, 1, 1, 3001, 9, 7, 3, 5, 3.88, 1, 0, 'vo_minigame_1012_result_1017', 'うわー惜しいわね！\\nもうちょっとで満点よ？\\nま、あたしでも悩む難問だから、\\nこの点数は胸を張っていいわ！');
insert into asm_reaction_data values (11300119, 1, 1, 3001, 6, 4, 1, 3, 4.12, 1, 0, 'vo_minigame_1012_result_1018', '正解率は半分くらいか～\\n悪くはないんだけど、あんたなら\\nこんなもんじゃないでしょ？');
insert into asm_reaction_data values (11300120, 1, 1, 3001, 6, 4, 1, 9, 4.34, 1, 0, 'vo_minigame_1012_result_1019', 'んーはっきり言っちゃうと\\n中途半端な点数ね…\\nまあいいわ！こっからガンガン\\n点数上げていくわよ！');
insert into asm_reaction_data values (11300121, 1, 1, 3001, 6, 4, 1, 3, 3.15, 1, 0, 'vo_minigame_1012_result_1020', 'う～ん、正直物足りない点数ね！\\nあんたには期待してんだから、\\nもっと頑張んなさい！');
insert into asm_reaction_data values (11300122, 1, 1, 3001, 6, 4, 2, 9, 5.3, 1, 0, 'vo_minigame_1012_result_1021', '半分くらいの正解率か\\n難しい問題だから仕方ないわね…\\nでもあんたはもっとできる！\\nだってあたしがついてんのよ！');
insert into asm_reaction_data values (11300123, 1, 1, 3001, 6, 4, 2, 8, 2.55, 1, 0, 'vo_minigame_1012_result_1022', 'うん、そこそこできんじゃない！\\n頑張って勉強して\\nさらに上を目指しましょ！');
insert into asm_reaction_data values (11300124, 1, 1, 3001, 6, 4, 2, 1, 4.19, 7, 0, 'vo_minigame_1012_result_1023', '難問なのにこの正解率は\\nよくやってる方よね！\\nでもこんなところで\\n満足してんじゃないわよ！？');
insert into asm_reaction_data values (11300125, 1, 1, 3001, 6, 4, 3, 7, 3.43, 1, 0, 'vo_minigame_1012_result_1024', '難問なのに半分くらい正解\\nできてんじゃない♪\\nこの調子でもっと学力\\n上げていきましょ！');
insert into asm_reaction_data values (11300126, 1, 1, 3001, 6, 4, 3, 1, 0.0, 1, 0, 'vo_minigame_1012_result_1025', 'よし、平均点ってとこね！\\nちゃんと勉強してるみたいで\\n安心したわ～♪');
insert into asm_reaction_data values (11300127, 1, 1, 3001, 6, 4, 3, 8, 3.72, 7, 0, 'vo_minigame_1012_result_1026', '難問揃いでこの正解率は\\n大したもんよ！\\nま、もっといい点取りたいんなら\\n勉強、付き合ったげるわ！');
insert into asm_reaction_data values (11300128, 1, 1, 3001, 3, 1, 1, 3, 3.5, 2, 1, 'vo_minigame_1012_result_1027', 'なるほど…\\nこれは教えがいがあるわね\\nビシバシ鍛えてやるから\\n覚悟しなさい！');
insert into asm_reaction_data values (11300129, 1, 1, 3001, 3, 1, 1, 4, 3.25, 2, 1, 'vo_minigame_1012_result_1028', 'ちょっとあんた、\\n全然できてないじゃない！\\n…まさかこれが本気だなんて\\n言わないわよね～？');
insert into asm_reaction_data values (11300130, 1, 1, 3001, 3, 1, 1, 3, 4.62, 2, 0, 'vo_minigame_1012_result_1029', 'うーん……適当に答えても\\nこれくらい正解できるわよ？\\nちょっと本腰入れて\\n教えないとね……！');
insert into asm_reaction_data values (11300131, 1, 1, 3001, 3, 1, 2, 9, 4.5, 1, 0, 'vo_minigame_1012_result_1030', '…ま、まあこの問題は\\nあんたには難しすぎたのかもね\\nちょっとずつでいいから、\\nレベルアップしていきましょ！');
insert into asm_reaction_data values (11300132, 1, 1, 3001, 3, 1, 2, 3, 0.01, 3, 9, 'vo_minigame_1012_result_1031', 'んー結構ミスっちゃってるわね…\\nこのまま続けるのもいいけど、\\n簡単な問題からやり直すのも\\nありかもよ～？');
insert into asm_reaction_data values (11300133, 1, 1, 3001, 3, 1, 2, 9, 0.01, 9, 9, 'vo_minigame_1012_result_1032', 'あらら、あんたにはちょっと\\n難しすぎたかしら…？\\nもう一回やり直しましょうか！');
insert into asm_reaction_data values (11300134, 1, 1, 3001, 3, 1, 3, 3, 0.01, 3, 6, 'vo_minigame_1012_result_1033', 'うーん、残念な結果ね…\\n超難問だから仕方ないけど\\n無理せず簡単な問題から挑戦\\nしてもいいかもよ？');
insert into asm_reaction_data values (11300135, 1, 1, 3001, 3, 1, 3, 3, 2.97, 9, 0, 'vo_minigame_1012_result_1034', '正解率はかなり悪いわね…\\nまあ難しい問題だもんね…！\\nそのチャレンジ精神は買うわ！');
insert into asm_reaction_data values (11300136, 1, 1, 3001, 3, 1, 3, 3, 3.1, 1, 0, 'vo_minigame_1012_result_1035', 'なんとか０点は免れたわね…\\n難問揃いだけど、\\nもっと頑張っていきましょ！');
insert into asm_reaction_data values (11300137, 1, 1, 3001, 0, 0, 1, 6, 4.31, 2, 1, 'vo_minigame_1012_result_1036', '…あんたさ、０点なんて\\n逆に取るの難しいわよ！？\\nまさか狙ったわけじゃ\\nないでしょーね～！？');
insert into asm_reaction_data values (11300138, 1, 1, 3001, 0, 0, 1, 2, 0.1, 2, 1, 'vo_minigame_1012_result_1037', '０点って…\\nあんたふざけてんの！？\\nちゃんとやらないなら\\n電撃魔法くらわせるわよ！？');
insert into asm_reaction_data values (11300139, 1, 1, 3001, 0, 0, 1, 9, 4.23, 3, 9, 'vo_minigame_1012_result_1038', 'もしかしたらあんたは\\n勉強向いてないのかもね…\\n…勉強だけがすべてじゃないわ\\n違うとこで頑張りましょ！');
insert into asm_reaction_data values (11300140, 1, 1, 3001, 0, 0, 2, 3, 4.38, 2, 0, 'vo_minigame_1012_result_1039', '怒んないから正直に言って？\\n…ふざけて答えたでしょ？\\nほら、正直に\\n言・い・な・さ・い？');
insert into asm_reaction_data values (11300141, 1, 1, 3001, 0, 0, 2, 8, 3.58, 2, 0, 'vo_minigame_1012_result_1040', 'あんたの点数は～～…\\n…はい！\u3000０てーん！！\\n…って、ふざけんなーー！！！');
insert into asm_reaction_data values (11300142, 1, 1, 3001, 0, 0, 2, 4, 2.02, 2, 1, 'vo_minigame_1012_result_1041', '０点ってどういうこと！？\\nいやあんた、逆にすごいわよ！？\\n目つぶってやったとしても\\n１点は取れるから！');
insert into asm_reaction_data values (11300143, 1, 1, 3001, 0, 0, 3, 9, 5.53, 1, 9, 'vo_minigame_1012_result_1042', 'あちゃー……残念だけど０点よ\\nちょっと難しすぎたかもねー…\\n…ま、こんなこともあるわ！\\n気を落とさなくていいわよ！');
insert into asm_reaction_data values (11300144, 1, 1, 3001, 0, 0, 3, 3, 4.4, 1, 9, 'vo_minigame_1012_result_1043', 'かなりの難問とはいえ、\\n０点はちょっと寂しいわね…\\nでもま、逆に考えるのよ！\\nあんたには伸びしろしかないわ！');
insert into asm_reaction_data values (11300145, 1, 1, 3001, 0, 0, 3, 3, 5.35, 1, 0, 'vo_minigame_1012_result_1044', '０点かー…うん、ごめん…\\n慰めの言葉が浮かばないわ！\\n……ま、次があるから\\n切り替えてくのよ！');
insert into asm_reaction_data values (12120101, 1, 2, 1201, 0, 0, 0, 8, 0.0, 8, 0, 'vo_minigame_1012_correct_132', 'OK！');
insert into asm_reaction_data values (12120102, 1, 2, 1201, 0, 0, 0, 7, 0.0, 7, 0, 'vo_minigame_1012_correct_133', '合ってる！');
