insert into asm_reaction_data values (12300101, 1, 2, 3001, -1, 20, 1, 7, 3.74, 1, 10, 'vo_minigame_1012_result_1045', 'はい、よくできました！\\n基礎はもう完璧ね！\\n次はもっと難しい問題にも\\nチャレンジしちゃいなさいよ！');
insert into asm_reaction_data values (12300102, 1, 2, 3001, -1, 20, 1, 1, 3.85, 9, 0, 'vo_minigame_1012_result_1046', 'なによあんた、走り出したペンが\\n止まらないって感じ？\\nったくシンプルにすごいじゃない\\n花丸あげるわ！');
insert into asm_reaction_data values (12300103, 1, 2, 3001, -1, 20, 1, 5, 0.01, 5, 8, 'vo_minigame_1012_result_1047', 'すごい点数ね…！\\nあんた勉強してないとか言って\\nホントはめちゃくちゃやってる\\nパターンのやつね！？');
insert into asm_reaction_data values (12300104, 1, 2, 3001, -1, 20, 2, 8, 2.86, 7, 4, 'vo_minigame_1012_result_1048', '勉強の成果、\\nちゃんとでてんじゃない！\\nあたしもあんたの先生として、\\n鼻が高いわ～♪');
insert into asm_reaction_data values (12300105, 1, 2, 3001, -1, 20, 2, 5, 2.02, 3, 9, 'vo_minigame_1012_result_1049', 'オッケー！\u3000もう十分よ！\\nこれ以上でき過ぎちゃったら、\\nあたしが教える必要なくなるわ！');
insert into asm_reaction_data values (12300106, 1, 2, 3001, -1, 20, 2, 5, 4.46, 1, 0, 'vo_minigame_1012_result_1050', '難しい問題を選んだつもりなのに\\nすごい正解数ね…！\\nでもまだ上がある…\\n次は最難関に挑戦よ！');
insert into asm_reaction_data values (12300107, 1, 2, 3001, -1, 20, 3, 5, 6.85, 4, 7, 'vo_minigame_1012_result_1051', 'すごいすごいとは思ってたけど、\\nあんた勉強も完璧なの…？\\nそりゃみんなあんたに惚れ…\\nや、な、なんでもない！！');
insert into asm_reaction_data values (12300108, 1, 2, 3001, -1, 20, 3, 5, 3.79, 9, 0, 'vo_minigame_1012_result_1052', 'この問題、あたしでも悩む\\n超難問なのに…\\nふふっ、もう褒めるしかないわ！\\n大変よくできました！');
insert into asm_reaction_data values (12300109, 1, 2, 3001, -1, 20, 3, 4, 0.01, 4, 7, 'vo_minigame_1012_result_1053', '別に顔赤くなんてなってない！\\n頭がいい人が好きとか…\\nかっこいいとか…\\n…思ってないからね！');
insert into asm_reaction_data values (12300110, 1, 2, 3001, -1, 20, 1, 5, 0.0, 5, 0, 'vo_minigame_1012_result_1054', 'スピードも正確さも完璧…\\n文句なしの満点だわ！\\nあんた将来、とんでもない人に\\nなっちゃうんじゃない！？');
insert into asm_reaction_data values (12300112, 1, 2, 3001, -1, 20, 2, 5, 0.0, 5, 0, 'vo_minigame_1012_result_1054', 'スピードも正確さも完璧…\\n文句なしの満点だわ！\\nあんた将来、とんでもない人に\\nなっちゃうんじゃない！？');
insert into asm_reaction_data values (12300114, 1, 2, 3001, -1, 20, 3, 5, 0.0, 5, 0, 'vo_minigame_1012_result_1054', 'スピードも正確さも完璧…\\n文句なしの満点だわ！\\nあんた将来、とんでもない人に\\nなっちゃうんじゃない！？');
insert into asm_reaction_data values (12300116, 1, 2, 3001, 19, 15, 1, 5, 3.0, 7, 10, 'vo_minigame_1012_result_1056', 'おお～かなり正解できてるわね！\\nこの調子でもっとすごい点\\n目指しちゃうわよ！');
insert into asm_reaction_data values (12300117, 1, 2, 3001, 19, 15, 1, 8, 0.01, 8, 10, 'vo_minigame_1012_result_1057', 'うん、バッチリいい感じよ！\\nちゃんと勉強してるみたいで\\n関心関心♪');
insert into asm_reaction_data values (12300118, 1, 2, 3001, 19, 15, 1, 5, 4.01, 8, 0, 'vo_minigame_1012_result_1058', 'え、こんなにいい点取れたのに\\nまだ満足してないの？\\nなによその向上心…\\nいいじゃない！');
insert into asm_reaction_data values (12300119, 1, 2, 3001, 19, 15, 2, 8, 2.83, 7, 10, 'vo_minigame_1012_result_1059', 'スピードも正解数もいい感じよ！\\nねえねえ、この調子で\\nてっぺん目指しちゃう？');
insert into asm_reaction_data values (12300120, 1, 2, 3001, 19, 15, 2, 10, 0.0, 10, 0, 'vo_minigame_1012_result_1060', 'この難易度でも\\nスラスラ答えちゃうなんて…\\nあんたって\\nほんとすごいやつよね…！');
insert into asm_reaction_data values (12300121, 1, 2, 3001, 19, 15, 2, 8, 3.66, 7, 4, 'vo_minigame_1012_result_1061', 'これだけ正解できたら\\n勉強も楽しいわよね♪\\nさ、まだまだ続けるわよ～！');
insert into asm_reaction_data values (12300122, 1, 2, 3001, 19, 15, 3, 5, 3.28, 8, 0, 'vo_minigame_1012_result_1062', 'あんた、この成績\\nまぐれじゃないわよね…！\\nこれだけできたら\\n大したもんだわ！');
insert into asm_reaction_data values (12300123, 1, 2, 3001, 19, 15, 3, 8, 2.7, 1, 0, 'vo_minigame_1012_result_1063', 'すごい！\u3000とってもいい成績よ！\\nこの難問も、あんたにかかりゃ\\nイチコロってやつ？');
insert into asm_reaction_data values (12300124, 1, 2, 3001, 19, 15, 3, 5, 3.98, 9, 9, 'vo_minigame_1012_result_1064', 'あんた…もしかして\\nあたしより点数いいかも？\\nあ、あたしもあんたを見習って\\n勉強しないとね…！');
insert into asm_reaction_data values (12300131, 1, 2, 3001, 14, 10, 1, 7, 2.51, 1, 0, 'vo_minigame_1012_result_1067', 'うん、なかなかいい点数よ！\\nでもまだまだ頑張れるわよね？\\nはい、次いきましょ！');
insert into asm_reaction_data values (12300132, 1, 2, 3001, 14, 10, 1, 1, 4.16, 7, 0, 'vo_minigame_1012_result_1068', '十分優秀な成績だけど\\nあんたならもっとできる！\\nさ、頑張って勉強するわよ！');
insert into asm_reaction_data values (12300133, 1, 2, 3001, 14, 10, 1, 8, 2.07, 7, 0, 'vo_minigame_1012_result_1069', 'うん、いい感じね！\\nこの調子で少しずつ、\\n正解数を増やしてくわよ！');
insert into asm_reaction_data values (12300134, 1, 2, 3001, 14, 10, 2, 8, 3.51, 1, 0, 'vo_minigame_1012_result_1070', '難問揃いなのに、\\nけっこーいい感じじゃない！\\nちゃんとできてるから\\n自信もっていいわよ！');
insert into asm_reaction_data values (12300135, 1, 2, 3001, 14, 10, 2, 1, 0.0, 1, 0, 'vo_minigame_1012_result_1071', '難しい問題でも基礎は大事よ！\\nこの調子でどんどん\\n点数上げていきましょう！');
insert into asm_reaction_data values (12300136, 1, 2, 3001, 14, 10, 2, 1, 4.3, 7, 0, 'vo_minigame_1012_result_1072', '10問以上取れてるわね！\\nえ、まだ物足りない？\\nフフ、じゃあもっと上\\n目指しちゃう？');
insert into asm_reaction_data values (12300137, 1, 2, 3001, 14, 10, 3, 8, 4.47, 7, 0, 'vo_minigame_1012_result_1073', 'うん、この難問でこの点数は\\n十分すぎる出来よね！\\nま、あんたならもっといい点\\n目指しちゃうんだろうけど♪');
insert into asm_reaction_data values (12300138, 1, 2, 3001, 14, 10, 3, 8, 3.68, 9, 0, 'vo_minigame_1012_result_1074', 'はいお疲れ～\\nなかなか良い点数じゃない\\n…あたしも勉強しないとね！');
insert into asm_reaction_data values (12300139, 1, 2, 3001, 14, 10, 3, 5, 3.34, 1, 0, 'vo_minigame_1012_result_1075', 'おお～10問以上\\n正解してんじゃない！\\nあんたやっぱり\\nただ者じゃないわね～');
insert into asm_reaction_data values (12300141, 1, 2, 3001, 14, 10, 1, 1, 6.58, 8, 0, 'vo_minigame_1012_result_1077', 'うん正解率は申し分なしね！\\nあとはもっと早く解ければ\\nもっと点数は伸びてくわよ！\\nこの調子で頑張っていきましょ！');
insert into asm_reaction_data values (12300143, 1, 2, 3001, 14, 10, 2, 1, 6.58, 8, 0, 'vo_minigame_1012_result_1077', 'うん正解率は申し分なしね！\\nあとはもっと早く解ければ\\nもっと点数は伸びてくわよ！\\nこの調子で頑張っていきましょ！');
insert into asm_reaction_data values (12300145, 1, 2, 3001, 14, 10, 3, 1, 6.58, 8, 0, 'vo_minigame_1012_result_1077', 'うん正解率は申し分なしね！\\nあとはもっと早く解ければ\\nもっと点数は伸びてくわよ！\\nこの調子で頑張っていきましょ！');
insert into asm_reaction_data values (12300146, 1, 2, 3001, 9, 5, 1, 1, 4.24, 7, 0, 'vo_minigame_1012_result_1078', 'ふ～ん、まあまあの出来だわ\\n悪くはないんだけど…あんたには\\nもっともっと期待してるわ～');
insert into asm_reaction_data values (12300147, 1, 2, 3001, 9, 5, 1, 7, 4.74, 1, 0, 'vo_minigame_1012_result_1079', 'うん、頑張ったけど…\\n正直もっと正解できるかもね～？\\nこんなのあんたには通過点！\\nさらに良い点目指してみない？');
insert into asm_reaction_data values (12300148, 1, 2, 3001, 9, 5, 1, 1, 0.0, 1, 0, 'vo_minigame_1012_result_1080', 'まあまあな点数だけど、\\n自分的に手ごたえはどう？\\nダメだって思ってんなら、\\nまだまだ伸びる余地ありね！');
insert into asm_reaction_data values (12300149, 1, 2, 3001, 9, 5, 2, 8, 2.21, 1, 0, 'vo_minigame_1012_result_1081', 'うん、中々の出来ね！\\nでもあんたはもっといい点\\n取れるはずよ！\\nもっと頑張りましょうか！');
insert into asm_reaction_data values (12300150, 1, 2, 3001, 9, 5, 2, 3, 2.46, 1, 0, 'vo_minigame_1012_result_1082', 'ん～はっきり言って微妙ね！\\nま、難しい問題だし、\\n勉強すれば\\n点数は上がっていくと思うわ！');
insert into asm_reaction_data values (12300151, 1, 2, 3001, 9, 5, 2, 3, 2.94, 1, 0, 'vo_minigame_1012_result_1083', 'ん～…\\n10点には届かなかったか～\\n次は10点越え目指して\\n頑張ってみない？');
insert into asm_reaction_data values (12300152, 1, 2, 3001, 9, 5, 3, 7, 4.19, 1, 0, 'vo_minigame_1012_result_1084', 'はいお疲れ～\\n点数的にはまあまあってとこね！\\nま、超難問だし頑張ったわよ');
insert into asm_reaction_data values (12300153, 1, 2, 3001, 9, 5, 3, 1, 0.0, 1, 0, 'vo_minigame_1012_result_1085', 'うん、かなり難しい問題なのに\\n最後までやり遂げたわね\\n次はもっといい点目指してみる？');
insert into asm_reaction_data values (12300154, 1, 2, 3001, 9, 5, 3, 3, 2.63, 1, 0, 'vo_minigame_1012_result_1086', 'ちょっとミスが多かったかもね～\\nでも間違えた所は復習して\\n次は正解するわよー！');
insert into asm_reaction_data values (12300155, 1, 2, 3001, 4, 1, 1, 3, 5.53, 1, 0, 'vo_minigame_1012_result_1087', 'あら…あんまり良くない点数ね～\\nどうしたの、調子でも悪かった？\\n次はもっと頑張りましょうか');
insert into asm_reaction_data values (12300156, 1, 2, 3001, 4, 1, 1, 3, 0.01, 3, 9, 'vo_minigame_1012_result_1088', 'ん～…正解数は\\n物足りないわね～\\nもうちょっと勉強の時間\\n増やしちゃおっか？');
insert into asm_reaction_data values (12300157, 1, 2, 3001, 4, 1, 1, 3, 4.15, 1, 3, 'vo_minigame_1012_result_1089', 'ん～…あんたならもうちょと\\nいい点取れんでしょ～？\\nもっと頑張んなさいよ\\n期待してやってんだからさ！');
insert into asm_reaction_data values (12300158, 1, 2, 3001, 4, 1, 2, 9, 0.01, 9, 9, 'vo_minigame_1012_result_1090', 'ん～今のあんたには、\\nこの問題は難しかったかしら…\\n難易度下げてチャレンジするのも\\nありかもね～？');
insert into asm_reaction_data values (12300159, 1, 2, 3001, 4, 1, 2, 3, 5.37, 1, 0, 'vo_minigame_1012_result_1091', 'あんまり出来は良くないわね～\\n難しい問題だししょうがないけど\\n次はもっと頑張ってほしいわ！');
insert into asm_reaction_data values (12300160, 1, 2, 3001, 4, 1, 2, 3, 1.44, 1, 0, 'vo_minigame_1012_result_1092', 'なるほど…\\nちょっと苦手な問題が多かった？\\nもう一度チャレンジ\\nしてみましょうか～');
insert into asm_reaction_data values (12300161, 1, 2, 3001, 4, 1, 3, 3, 0.0, 3, 0, 'vo_minigame_1012_result_1093', 'んん～…問題が難しすぎた？\\n無理に難しい問題続けるより、\\n難易度下げた方が\\n勉強の効率良いかもよ～？');
insert into asm_reaction_data values (12300162, 1, 2, 3001, 4, 1, 3, 3, 2.91, 9, 3, 'vo_minigame_1012_result_1094', '…あんまり点数取れなかったわね\\nこれはあたしにも難しい問題だし\\nそう落ち込まなくても大丈夫！\\n次頑張りましょ！');
insert into asm_reaction_data values (12300163, 1, 2, 3001, 4, 1, 3, 5, 2.61, 1, 0, 'vo_minigame_1012_result_1095', 'ごめん、ちょっと難しすぎた？\\nもう一度チャレンジするも良し、\\n難易度を下げるも良し、\\nあんたがやる気なら付き合うわ！');
insert into asm_reaction_data values (12300164, 1, 2, 3001, 0, 0, 1, 4, 3.63, 2, 1, 'vo_minigame_1012_result_1096', 'ちょっとあんた…\\nやる気ないわよね～！？\\n次こんな点数取ったら\\n怒るわよ！');
insert into asm_reaction_data values (12300165, 1, 2, 3001, 0, 0, 1, 6, 4.16, 2, 1, 'vo_minigame_1012_result_1097', 'はあ…自分で何点取ったか\\n分かってるわよね～…？\\n０点よ０点！\u3000舐めてんの！？');
insert into asm_reaction_data values (12300166, 1, 2, 3001, 0, 0, 1, 3, 0.01, 3, 6, 'vo_minigame_1012_result_1098', 'うう～頭痛い…\\nあんたのせいよ！\\nなに０点って！\\nはあ、このままじゃ赤点よ～…');
insert into asm_reaction_data values (12300167, 1, 2, 3001, 0, 0, 2, 6, 5.75, 2, 0, 'vo_minigame_1012_result_1099', 'ねえ、あんた本気でやったの？\\nまさか適当にやるわけないわよね\\n…分かった、\\nもう一回チャレンジするのよ！');
insert into asm_reaction_data values (12300168, 1, 2, 3001, 0, 0, 2, 4, 5.64, 2, 1, 'vo_minigame_1012_result_1100', 'あ…あんた、０点よ０点…！\\nあたしの教え方が悪かった…？\\n…燃えてきたわ！\\n絶対あんたの学力上げてやる！');
insert into asm_reaction_data values (12300169, 1, 2, 3001, 0, 0, 2, 8, 5.73, 4, 8, 'vo_minigame_1012_result_1101', 'ちょっと待って採点ミスかも…\\n…いや合ってるわね。はい０点\\n…って０点！？\\nふざけんなーー！');
insert into asm_reaction_data values (12300170, 1, 2, 3001, 0, 0, 3, 5, 5.32, 3, 1, 'vo_minigame_1012_result_1102', 'あらら…０点よ\\nま、難しい問題だしね…\\n…つっても０点は無いわ！\\n一問くらい正解しなさいよ！');
insert into asm_reaction_data values (12300171, 1, 2, 3001, 0, 0, 3, 3, 2.37, 9, 9, 'vo_minigame_1012_result_1103', '残念だけど０点よ\\nま、まあ前向きにとらえるなら、\\n今が底よ！\u3000どん底！\\nあとは上がってくだけね！');
insert into asm_reaction_data values (12300172, 1, 2, 3001, 0, 0, 3, 9, 4.25, 1, 3, 'vo_minigame_1012_result_1104', '…かなり出来が悪いわね\\n一旦休憩しましょうか？\\nリフレッシュして頭切り替えて\\nもう一度頑張りましょう！');
insert into asm_reaction_data values (13100101, 1, 3, 1001, 0, 0, 0, 7, 0.0, 7, 0, 'vo_minigame_1012_gamestart_100', 'さ、勉強を始めるわよ');
insert into asm_reaction_data values (13100102, 1, 3, 1001, 0, 0, 0, 1, 0.0, 1, 0, 'vo_minigame_1012_gamestart_101', 'よし、勉強の成果を見てやるわ！');
insert into asm_reaction_data values (13100103, 1, 3, 1001, 0, 0, 0, 1, 1.82, 7, 0, 'vo_minigame_1012_gamestart_102', 'じゃあ試験するわよ。はい教科書閉じて！');
insert into asm_reaction_data values (13100201, 1, 3, 1002, -1, 3, 0, 8, 0.01, 8, 4, 'vo_minigame_1012_gamestart_103', 'やる気マンマンじゃない！');
insert into asm_reaction_data values (13100202, 1, 3, 1002, -1, 3, 0, 1, 0.0, 1, 0, 'vo_minigame_1012_gamestart_104', 'よし、じゃあもう一回やるわよ！');
insert into asm_reaction_data values (13100301, 1, 3, 1003, 1, 1, 0, 0, 0.0, 0, 0, 'vo_minigame_1012_gamestart_105', '普通の難易度よ！');
insert into asm_reaction_data values (13100302, 1, 3, 1003, 1, 1, 0, 7, 0.0, 7, 0, 'vo_minigame_1012_gamestart_106', 'まずは基本からね！');
insert into asm_reaction_data values (13100303, 1, 3, 1003, 2, 2, 0, 10, 0.0, 10, 0, 'vo_minigame_1012_gamestart_107', '難しい問題に挑戦するのね！');
insert into asm_reaction_data values (13100304, 1, 3, 1003, 2, 2, 0, 1, 0.67, 8, 0, 'vo_minigame_1012_gamestart_108', 'よし、あんたならできるわ！');
insert into asm_reaction_data values (13100305, 1, 3, 1003, 3, 3, 0, 5, 0.0, 5, 0, 'vo_minigame_1012_gamestart_109', 'あたしでも手こずる難問揃いよ…！');
insert into asm_reaction_data values (13100306, 1, 3, 1003, 3, 3, 0, 2, 0.0, 2, 0, 'vo_minigame_1012_gamestart_110', '激ムズだけど頑張んなさい！');
insert into asm_reaction_data values (13100401, 1, 3, 1004, 0, 0, 0, 7, 0.0, 7, 0, 'vo_minigame_1012_gamestart_111', '鉄は熱いうちに打て、\\n…ってね♪');
insert into asm_reaction_data values (13100402, 1, 3, 1004, 0, 0, 0, 1, 0.0, 1, 0, 'vo_minigame_1012_gamestart_112', 'よし、もっぺんやるわよ！');
insert into asm_reaction_data values (13100501, 1, 3, 1005, 0, 0, 0, 9, 0.0, 9, 0, 'vo_minigame_1012_gamestart_113', 'スズナもちゃんと勉強してるみたいね～');
insert into asm_reaction_data values (13100502, 1, 3, 1005, 0, 0, 0, 3, 0.0, 3, 0, 'vo_minigame_1012_gamestart_114', 'あんたがスズナの\\n先生？\u3000…ふーん');
insert into asm_reaction_data values (13110101, 1, 3, 1101, 0, 0, 0, 1, 0.0, 1, 0, 'vo_minigame_1012_start_100', '問題！');
insert into asm_reaction_data values (13110102, 1, 3, 1101, 0, 0, 0, 1, 0.0, 1, 0, 'vo_minigame_1012_start_101', 'いくわよ！');
insert into asm_reaction_data values (13110103, 1, 3, 1101, 0, 0, 0, 7, 0.0, 7, 0, 'vo_minigame_1012_start_102', '解けるかしら？');
insert into asm_reaction_data values (13110201, 1, 3, 1102, 0, 0, 0, 2, 0.0, 2, 0, 'vo_minigame_1012_start_103', '次はいける！');
insert into asm_reaction_data values (13110202, 1, 3, 1102, 0, 0, 0, 1, 0.0, 1, 0, 'vo_minigame_1012_start_104', '諦めないで！');
insert into asm_reaction_data values (13110203, 1, 3, 1102, 0, 0, 0, 1, 0.0, 1, 0, 'vo_minigame_1012_start_105', '取り返すのよ！');
insert into asm_reaction_data values (13110301, 1, 3, 1103, 4, 2, 0, 1, 0.0, 1, 0, 'vo_minigame_1012_start_106', 'さあ次よ！');
insert into asm_reaction_data values (13110302, 1, 3, 1103, 4, 2, 0, 1, 0.0, 1, 0, 'vo_minigame_1012_start_107', '落ち着いてね！');
insert into asm_reaction_data values (13110303, 1, 3, 1103, 4, 2, 0, 7, 0.0, 7, 0, 'vo_minigame_1012_start_108', 'これは解ける？');
insert into asm_reaction_data values (13110304, 1, 3, 1103, 7, 5, 0, 2, 0.0, 2, 0, 'vo_minigame_1012_start_109', 'まだ気を抜かないで！');
insert into asm_reaction_data values (13110305, 1, 3, 1103, 7, 5, 0, 1, 0.0, 1, 0, 'vo_minigame_1012_start_110', 'ほら、次いくわよ！');
insert into asm_reaction_data values (13110306, 1, 3, 1103, 7, 5, 0, 8, 0.0, 8, 0, 'vo_minigame_1012_start_111', 'まだまだ続くわよ！');
insert into asm_reaction_data values (13110307, 1, 3, 1103, 10, 8, 0, 2, 0.0, 2, 0, 'vo_minigame_1012_start_112', '最後まで集中よ！');
insert into asm_reaction_data values (13110308, 1, 1, 1103, 10, 8, 0, 8, 0.0, 8, 0, 'vo_minigame_1012_start_113', 'ラストスパート！');
insert into asm_reaction_data values (13110309, 1, 1, 1103, 10, 8, 0, 1, 0.0, 1, 0, 'vo_minigame_1012_start_114', '走り切って！');
