insert into asm_reaction_data values (22300152, 2, 2, 3001, 9, 5, 3, 0, 3.55, 3, 0, 'vo_minigame_1012_result_2084', '激ムズだけど\\nやることは一緒だよね？\\nうちもヒデサイについてくから\\nコツコツがんばろ！');
insert into asm_reaction_data values (22300153, 2, 2, 3001, 9, 5, 3, 4, 2.51, 6, 0, 'vo_minigame_1012_result_2085', 'やっぱおにムズだね…\\nそだ、迷ったら\\nヒント使うのも\\nありよりのあり？');
insert into asm_reaction_data values (22300154, 2, 2, 3001, 9, 5, 3, 9, 6.15, 5, 0, 'vo_minigame_1012_result_2086', 'やっぱテストって\\nなんとなくじゃ無理？\\n覚えるしかないの？\\nじゃあがんばるしかないね…');
insert into asm_reaction_data values (22300155, 2, 2, 3001, 4, 1, 1, 4, 4.12, 9, 6, 'vo_minigame_1012_result_2087', 'できたと思ったけど\\nそーじゃなかった系？\\nテストってマジきびしー…');
insert into asm_reaction_data values (22300156, 2, 2, 3001, 4, 1, 1, 4, 0.01, 4, 6, 'vo_minigame_1012_result_2088', 'うーん…さっぱり！\\nでも簡単な問題なんだよね…？\\nもっかいやってみる？');
insert into asm_reaction_data values (22300157, 2, 2, 3001, 4, 1, 1, 0, 5.28, 3, 0, 'vo_minigame_1012_result_2089', 'うちらまだまだ\\nベンキョーちうだし…\\nこれからだよねっ？\\nね、ヒデサイ！');
insert into asm_reaction_data values (22300158, 2, 2, 3001, 4, 1, 2, 0, 2.89, 3, 0, 'vo_minigame_1012_result_2090', 'ちょっとずつ覚えれば\\nおーけーっしょ！\\nうちと一緒に\\nベンキョーだね！');
insert into asm_reaction_data values (22300159, 2, 2, 3001, 4, 1, 2, 0, 5.45, 7, 0, 'vo_minigame_1012_result_2091', 'うちベンキョー苦手でも\\nヒデサイとベンキョー\\nするのは好き！\u3000だから\\nもっかい教えてくれる？');
insert into asm_reaction_data values (22300160, 2, 2, 3001, 4, 1, 2, 4, 4.29, 10, 3, 'vo_minigame_1012_result_2092', '覚えても、すぐ忘れるんだけど\\nどしたらいい？\\nあ、そーゆうとき\\nフクシューする感じ？');
insert into asm_reaction_data values (22300161, 2, 2, 3001, 4, 1, 3, 4, 4.64, 8, 6, 'vo_minigame_1012_result_2093', 'ムズ過ぎ！\\n頭パンクするかと思った…！\\nヒデサイ、うちの頭\\nふぅふぅして～');
insert into asm_reaction_data values (22300162, 2, 2, 3001, 4, 1, 3, 9, 3.14, 5, 0, 'vo_minigame_1012_result_2094', 'おにムズ過ぎてテンサゲ～\\nでもヒデサイがんばってるし\\nうちもがんばる！');
insert into asm_reaction_data values (22300163, 2, 2, 3001, 4, 1, 3, 7, 6.59, 4, 0, 'vo_minigame_1012_result_2095', 'ヒデサイと同じ点数で\\nちょっち安心したかも\\n一緒にがんばろーね！\\n置いてっちゃやだよ？');
insert into asm_reaction_data values (22300164, 2, 2, 3001, 0, 0, 1, 3, 0.0, 3, 0, 'vo_minigame_1012_result_2096', '…まあ、これより下はないし\\n次は大逆転\\n点数爆上がりっしょ！');
insert into asm_reaction_data values (22300165, 2, 2, 3001, 0, 0, 1, 9, 2.2, 10, 5, 'vo_minigame_1012_result_2097', '０点じゃん…\\nそだ、次はえんぴつ転がして\\n選ぶ作戦やってみる？');
insert into asm_reaction_data values (22300166, 2, 2, 3001, 0, 0, 1, 4, 0.01, 4, 6, 'vo_minigame_1012_result_2098', '考えるの無理な時あるよね…\\nヒデサイもそーゆう\\n感じだったの？');
insert into asm_reaction_data values (22300167, 2, 2, 3001, 0, 0, 2, 6, 2.8, 2, 3, 'vo_minigame_1012_result_2099', 'え、ヒデサイも０点？\\nじゃあうちと一緒じゃん♪\\nまあ焦んないで\\nベンキョーしてこーよ！');
insert into asm_reaction_data values (22300168, 2, 2, 3001, 0, 0, 2, 9, 3.22, 4, 6, 'vo_minigame_1012_result_2100', 'むむむ～…０点…！\\n覚えてもすぐ忘れちゃうし\\nベンキョーってマジ大変');
insert into asm_reaction_data values (22300169, 2, 2, 3001, 0, 0, 2, 4, 2.1, 0, 11, 'vo_minigame_1012_result_2101', '０点だね…\\nでも、へーきへーき\\nリベンジしたら、結果オーライ！');
insert into asm_reaction_data values (22300170, 2, 2, 3001, 0, 0, 3, 0, 2.74, 2, 3, 'vo_minigame_1012_result_2102', 'おやつ休憩して\\nリベンジしよっ！\\n甘いの食べたら、イケるっしょ！');
insert into asm_reaction_data values (22300171, 2, 2, 3001, 0, 0, 3, 6, 3.0, 9, 9, 'vo_minigame_1012_result_2103', 'ヒデサイでも\\nおにムズな感じ？\\nじゃあ、このテスト\\n誰も解けなくない？');
insert into asm_reaction_data values (22300172, 2, 2, 3001, 0, 0, 3, 10, 4.37, 2, 0, 'vo_minigame_1012_result_2104', '…あれ？\\n０が〇に見えてきた！\\nきゃはっ、ちょっち\\nやる気出てきたかも！');
insert into asm_reaction_data values (23100101, 2, 3, 1001, 0, 0, 0, 0, 0.01, 0, 10, 'vo_minigame_1012_gamestart_200', 'よーし、がんばるぞー');
